### Issue URL (Ads)
 [https://mail.yandex.ru/](https://adguardteam.github.io/AnonymousRedirect/redirect.html?url=https%3A%2F%2Fmail.yandex.ru%2F)
### Comment
> Не блокируется реклама на сайте почты Яндекс. Но я написал JavaScript, который делает это, реализуйте его в своих следующих версиях:
> 
> (function() {
>     function removeAds() {
>         const layout = document.querySelector('#js-mail-layout');
>         if (!layout) return;
> 
>         const body = layout.querySelector('[class*="PageLayout-m__body"]');
>         if (!body) return;
> 
>         const children = Array.from(body.children);
> 
>         children.forEach((el, index) => {
>             if (index === children.length - 1 && el.offsetWidth < 500) {
>                 el.remove();
>             }
>         });
>     }
> 
>     const observer = new MutationObserver(removeAds);
>     observer.observe(document.body, { childList: true, subtree: true });
> 
>     removeAds();
> })();

